"use client"

import { useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import type { ReactNode } from 'react';

interface BoundingBox {
  x: number;
  y: number;
  w: number;
  h: number;
  targetW: number;
  targetH: number;
  life: number;
  decay: number;
}

interface ClickBoundingBoxProps {
  color?: string;
  lineWidth?: number;
  decay?: number;
  minSize?: number;
  maxSize?: number;
  cornerLen?: number;
  children?: ReactNode;
}

export default function ClickBoundingBox({
  color = '#fff',
  lineWidth = 1,
  decay = 0.015,
  minSize = 40,
  maxSize = 60,
  cornerLen = 8,
  children,
}: ClickBoundingBoxProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const boxesRef = useRef<BoundingBox[]>([]);
  const isRunningRef = useRef<boolean>(false);
  const animationIdRef = useRef<number | null>(null);

  // Sync canvas to full viewport
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const syncSize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    syncSize();
    window.addEventListener('resize', syncSize);
    return () => window.removeEventListener('resize', syncSize);
  }, []);

  const startLoop = () => {
    if (isRunningRef.current) return;
    isRunningRef.current = true;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const draw = () => {
      if (boxesRef.current.length === 0) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        isRunningRef.current = false;
        return;
      }

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      boxesRef.current = boxesRef.current.filter((p: BoundingBox) => {
        p.life -= p.decay;
        if (p.life <= 0) return false;

        p.w += (p.targetW - p.w) * 0.15;
        p.h += (p.targetH - p.h) * 0.15;

        const hw = p.w / 2;
        const hh = p.h / 2;
        const cl = cornerLen;

        ctx.globalAlpha = Math.max(0, p.life);

        ctx.save();
        ctx.translate(p.x, p.y);

        // Faint full box outline
        ctx.beginPath();
        ctx.rect(-hw, -hh, p.w, p.h);
        ctx.lineWidth = lineWidth;
        ctx.strokeStyle = `rgba(255,255,255,${p.life * 0.3})`;
        ctx.stroke();

        // Bold corner brackets
        ctx.beginPath();
        ctx.moveTo(-hw, -hh + cl);
        ctx.lineTo(-hw, -hh);
        ctx.lineTo(-hw + cl, -hh);
        ctx.moveTo(hw - cl, -hh);
        ctx.lineTo(hw, -hh);
        ctx.lineTo(hw, -hh + cl);
        ctx.moveTo(-hw, hh - cl);
        ctx.lineTo(-hw, hh);
        ctx.lineTo(-hw + cl, hh);
        ctx.moveTo(hw - cl, hh);
        ctx.lineTo(hw, hh);
        ctx.lineTo(hw, hh - cl);

        ctx.lineWidth = lineWidth * 2;
        ctx.strokeStyle = color;
        ctx.stroke();

        // Label tag
        ctx.fillStyle = `rgba(255,255,255,${p.life})`;
        ctx.fillRect(-hw, -hh - 10, 36, 10);
        ctx.fillStyle = `rgba(0,0,0,${p.life})`;
        ctx.font = '8px monospace';
        ctx.textAlign = 'left';
        ctx.textBaseline = 'top';
        ctx.fillText('OBJ 0.99', -hw + 2, -hh - 8);

        ctx.restore();

        return true;
      });

      ctx.globalAlpha = 1;
      animationIdRef.current = requestAnimationFrame(draw);
    };

    animationIdRef.current = requestAnimationFrame(draw);
  };

  useEffect(() => {
    return () => {
      if (animationIdRef.current !== null) {
        cancelAnimationFrame(animationIdRef.current);
      }
    };
  }, []);

  // clientX/Y maps directly to fixed canvas — no rect offset needed
  const handleClick = (e: React.MouseEvent) => {
    boxesRef.current.push({
      x: e.clientX,
      y: e.clientY,
      w: 0,
      h: 0,
      targetW: minSize + Math.random() * (maxSize - minSize),
      targetH: minSize + Math.random() * (maxSize - minSize),
      life: 1.0,
      decay,
    });

    startLoop();
  };

  return (
    <>
      <div style={{ display: 'contents' }} onClick={handleClick}>
        {children}
      </div>

      {typeof window !== 'undefined' &&
        createPortal(
          <canvas
            ref={canvasRef}
            style={{
              position: 'fixed',
              top: 0,
              left: 0,
              width: '100vw',
              height: '100vh',
              pointerEvents: 'none',
              zIndex: 9999,
            }}
          />,
          document.body
        )}
    </>
  );
}
